arguments.command:
mkdir -p /tmp/sv-8104114796ee444d9c803945ab892236/typed-meta && cd /tmp/sv-8104114796ee444d9c803945ab892236/typed-meta && dotnet new console --framework net11.0 -o . --force -n TypedMeta > /dev/null 2>&1 && cat > Program.cs << 'EOF'
using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed metadata retrieval — returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Typed metadata for Person: {personInfo.Type.Name}");

var json = JsonSerializer.Serialize(new Person("Alice", 30), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2) Probe without throwing — TryGetTypeInfo returns false if unavailable
bool found = options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info);
Console.WriteLine($"\nTryGetTypeInfo(Person): found={found}, type={info?.Type.Name}");

// Probe for a type whose metadata is NOT available (empty resolver)
var restrictedOptions = new JsonSerializerOptions
{
    TypeInfoResolver = JsonTypeInfoResolver.Combine() // resolves nothing
};

bool notFound = restrictedOptions.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? missing);
Console.WriteLine($"TryGetTypeInfo(Person) on empty resolver: found={notFound}, info={missing?.Type.Name ?? "null"}");

public record Person(string Name, int Age);
EOF
